namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;
static constexpr uint32_t HARD_CAP_ELEMS = 16384;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

// Compute output spatial dimension given input size, kernel, stride, padding, ceil_mode
static inline uint32_t OutputDim(uint32_t in, uint32_t kernel, uint32_t stride, uint32_t pad, bool ceil) {
    if (ceil)
        return CeilDiv(in + 2 * pad - (kernel - 1) - 1, stride) + 1;
    else
        return (in + 2 * pad - (kernel - 1) - 1) / stride + 1;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    MaxPooling3dCustomTilingData tiling;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();

    // Get input shape
    const gert::Shape *x_shape = context->GetInputShape(0)->GetOriginShape();
    uint32_t n = static_cast<uint32_t>(x_shape->GetDim(0));
    uint32_t c = static_cast<uint32_t>(x_shape->GetDim(1));
    uint32_t d = static_cast<uint32_t>(x_shape->GetDim(2));
    uint32_t h = static_cast<uint32_t>(x_shape->GetDim(3));
    uint32_t w = static_cast<uint32_t>(x_shape->GetDim(4));
    uint32_t totalElements = n * c * d * h * w;

    // Get pooling attributes (using defaults if not provided)
    uint32_t kernel_size = static_cast<uint32_t>(attrs->GetAttrPointer<int>(0)[0]);
    uint32_t stride = static_cast<uint32_t>(attrs->GetAttrPointer<int>(1)[0]);
    uint32_t padding = static_cast<uint32_t>(attrs->GetAttrPointer<int>(2)[0]);
    bool return_indices = attrs->GetAttrPointer<bool>(3)[0];
    bool ceil_mode = attrs->GetAttrPointer<bool>(4)[0];
    (void)return_indices; // not used in output

    // Compute output spatial dimensions
    uint32_t od = OutputDim(d, kernel_size, stride, padding, ceil_mode);
    uint32_t oh = OutputDim(h, kernel_size, stride, padding, ceil_mode);
    uint32_t ow = OutputDim(w, kernel_size, stride, padding, ceil_mode);
    uint32_t outputElements = n * c * od * oh * ow;

    // Tiling: tile over the output elements? We'll tile over input spatial sub-blocks.
    // For each tile we process a 3D block of input that generates a 3D block of output.
    // We'll define tile as number of input elements per tile (including channels?).
    // Since UB is per block, we need to fit input tile, output tile and workspace.
    // For simplicity, we process one channel at a time, and within channel a small spatial volume.
    // Let’s set tileLength = number of input elements in a spatial sub-block * channels? Actually we can process all channels per spatial tile.
    // Budget: need to load input tile (float) + output tile + workspace (temp for per-kernel max).
    // Let each tile cover a 3D block of size (tileD, tileH, tileW) in the input, all channels.
    // Input tile size = channels * tileD * tileH * tileW floats.
    // Output tile size = channels * (tileD/stride approx) * (tileH/stride) * (tileW/stride) floats.
    // Constraint: input + output <= UB_BUDGET_BYTES / sizeof(float) = 48k elements.
    // We'll choose tileD, tileH, tileW such that product * C * (1 + 1/(stride^3)) <= 48k.
    // Since C can be large (32), we may tile also over channels? But we can reduce tile spatial size.
    // Approximation: set tileLength = number of input elements (including channels) per tile.
    // For robust, use a smaller fixed tileSize like 8192 elements (including channels).
    uint32_t maxTile = UB_BUDGET_BYTES / (2 * sizeof(float)); // assume input + output same size
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = maxTile;
    if (totalElements < tileLen) {
        tileLen = AlignDown(totalElements, ALIGN_ELEMS);
        if (tileLen == 0) tileLen = totalElements;
    }

    // Block dim: proportional to number of tiles, but cap for stability
    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalElements, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalElements);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_n(n);
    tiling.set_c(c);
    tiling.set_d(d);
    tiling.set_h(h);
    tiling.set_w(w);
    tiling.set_kernel_size(kernel_size);
    tiling.set_stride(stride);
    tiling.set_padding(padding);
    tiling.set_ceil_mode(ceil_mode ? 1u : 0u);
    tiling.set_od(od);
    tiling.set_oh(oh);
    tiling.set_ow(ow);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

