class KernelMaxPooling3dCustom {
public:
    __aicore__ inline KernelMaxPooling3dCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t n, uint32_t c, uint32_t d, uint32_t h, uint32_t w,
                                uint32_t kernel_size, uint32_t stride, uint32_t padding,
                                uint32_t ceil_mode,
                                uint32_t od, uint32_t oh, uint32_t ow) {
        n_ = n; c_ = c; d_ = d; h_ = h; w_ = w;
        k_ = kernel_size; s_ = stride; p_ = padding;
        ceil_ = ceil_mode;
        od_ = od; oh_ = oh; ow_ = ow;
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, od_ * oh_ * ow_ * c_ * n_);

        // Buffer for input tile: we process one channel at a time for simplicity.
        // Tile size for input spatial sub-block: we use a 3D block of size (td, th, tw)
        // We'll compute td,th,tw based on tileLen and channels.
        // But we need to define tiling at Init? Instead we derive per iteration.
        // For simplicity, we allocate buffers of fixed max size.
        // Let maxTileD = 16, maxTileH = 16, maxTileW = 16.
        // Input = channels * maxTileD * maxTileH * maxTileW = 32*4096 = 131072 floats -> too big.
        // We'll handle per channel: each channel's spatial tile can be up to 4096 elements (e.g., 16x16x16).
        // So allocate tile size = maxTileD * maxTileH * maxTileW = 4096 (constant).
        // We'll use tileLen as number of input elements per channel? We'll ignore and use fixed.
        // Actually we need to adapt. For simplicity, we'll process each channel independently.
        // For each output pixel, we need to load a 3x3x3 region. We can compute on the fly using global memory loads.
        // That might be inefficient but ok for demonstration.
        // We'll use AscendC local memory for tiles of one output plane.
        // Simplify: we process one output slice (od x oh) at a time, all channels? Too large.
        // Let's process one output point at a time, using scalar loads.
        // But then we cannot use vectorization. The leaky_relu example used vector ops. For max pooling we can use vector max? Not for sliding window.
        // We'll implement a naive loop over output pixels, loading the 27 values from global, computing max, storing.
        // This will be slow but correct. We'll still use double buffering for input? Not needed.
        // We'll skip pipelining and just loop over output elements per block.
        // To satisfy the structure, we'll implement Process() that for each output element within the block's assigned range, compute.
        // The block assignment: each block handles a chunk of output elements (flattened).
        // We'll compute mapping from output index to (n,c,od,oh,ow) and then compute input region.
        // This is a valid kernel.
        // Use double buffering? We'll keep the pipeline structure but with dummy ops? Better to keep simple.
        // I'll implement a straightforward loop without pipelining to avoid complexity.
        // The user expects a valid kernel, not necessarily optimal.
        // So we'll implement Process() as a simple loop over output elements assigned to this block.
        // We won't use CopyIn/CopyOut pipeline; we'll just use global loads and stores directly.
        // But we need to use AscendC tensor types? LocalTensor? We can use GlobalTensor.
        // AscendC kernel can access global memory directly.
        // Let's implement that.
    }

    __aicore__ inline void Process() {
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());

        uint32_t totalOutput = n_ * c_ * od_ * oh_ * ow_;
        uint32_t chunkSize = (totalOutput + blockNum - 1) / blockNum;
        uint32_t start = blockIdx * chunkSize;
        uint32_t end = start + chunkSize;
        if (end > totalOutput) end = totalOutput;

        for (uint32_t idx = start; idx < end; ++idx) {
            // Decompose idx into (n, c, od, oh, ow)
            uint32_t ow_idx = idx % ow_;
            uint32_t temp = idx / ow_;
            uint32_t oh_idx = temp % oh_;
            temp /= oh_;
            uint32_t od_idx = temp % od_;
            temp /= od_;
            uint32_t c_idx = temp % c_;
            uint32_t n_idx = temp / c_;

            // Compute input coordinates with padding
            int32_t in_d = static_cast<int32_t>(od_idx * s_) - static_cast<int32_t>(p_);
            int32_t in_h = static_cast<int32_t>(oh_idx * s_) - static_cast<int32_t>(p_);
            int32_t in_w = static_cast<int32_t>(ow_idx * s_) - static_cast<int32_t>(p_);

            float max_val = -3.4028235e+38f; // -FLT_MAX

            // Loop over kernel volume
            for (uint32_t kd = 0; kd < k_; ++kd) {
                int32_t id = in_d + static_cast<int32_t>(kd);
                if (id < 0 || id >= static_cast<int32_t>(d_)) continue;
                for (uint32_t kh = 0; kh < k_; ++kh) {
                    int32_t ih = in_h + static_cast<int32_t>(kh);
                    if (ih < 0 || ih >= static_cast<int32_t>(h_)) continue;
                    for (uint32_t kw = 0; kw < k_; ++kw) {
                        int32_t iw = in_w + static_cast<int32_t>(kw);
                        if (iw < 0 || iw >= static_cast<int32_t>(w_)) continue;

                        // Compute global offset for input element
                        uint32_t offset = ((n_idx * c_ + c_idx) * d_ + static_cast<uint32_t>(id)) * h_ * w_
                                        + static_cast<uint32_t>(ih) * w_ + static_cast<uint32_t>(iw);
                        float val = xGm_.GetValue(offset);
                        if (val > max_val) max_val = val;
                    }
                }
            }

            // Store output
            uint32_t output_offset = ((n_idx * c_ + c_idx) * od_ + od_idx) * oh_ * ow_
                                    + oh_idx * ow_ + ow_idx;
            yGm_.SetValue(output_offset, max_val);
        }
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    uint32_t n_, c_, d_, h_, w_;
    uint32_t k_, s_, p_;
    uint32_t ceil_;
    uint32_t od_, oh_, ow_;
    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

